318	// ── Error-report functions ─────────────────────────────────────────────────────
319	
320	/// Push an error for argument `arg` with extra message `extramsg`.
321	/// Attempts to enrich the message with the calling function's name.
322	/// Always returns `Err`.
323	///
324	/// C: `LUALIB_API int luaL_argerror(lua_State *L, int arg, const char *extramsg)`
325	pub fn arg_error(
326	    state: &mut LuaState,
327	    mut arg: i32,
328	    extramsg: &[u8],
329	) -> Result<usize, LuaError> {
330	    let mut ar = LuaDebug::default();
331	    if !state.get_stack(0, &mut ar) {
332	        // C: return luaL_error(L, "bad argument #%d (%s)", arg, extramsg);
333	        return Err(LuaError::runtime(format_args!(
334	            "bad argument #{} ({})",
335	            arg,
336	            BStr(extramsg)
337	        )));
338	    }
339	    state.get_info(b"n", &mut ar)?;
340	    if ar.namewhat == b"method" {
341	        arg -= 1; // do not count 'self'
342	        if arg == 0 {
343	            let name = ar.name.clone().unwrap_or_else(|| b"?".to_vec());
344	            return Err(LuaError::runtime(format_args!(
345	                "calling '{}' on bad self ({})",
346	                BStr(&name),
347	                BStr(extramsg)
348	            )));
349	        }
350	    }
351	    let fname = if ar.name.is_none() {
352	        if push_global_func_name(state, &mut ar)? {
353	            state.peek_bytes(-1).unwrap_or_else(|| b"?".to_vec())
354	        } else {
355	            b"?".to_vec()
356	        }
357	    } else {
358	        ar.name.clone().unwrap_or_else(|| b"?".to_vec())
359	    };
360	    Err(LuaError::runtime(format_args!(
361	        "bad argument #{} to '{}' ({})",
362	        arg,
363	        BStr(&fname),
364	        BStr(extramsg)
365	    )))
366	}
367	
368	/// Push a type-mismatch error for argument `arg`, stating `tname` was expected.
369	/// Always returns `Err`.
370	///
371	/// C: `LUALIB_API int luaL_typeerror(lua_State *L, int arg, const char *tname)`
372	pub fn type_error_arg(
373	    state: &mut LuaState,
374	    arg: i32,
375	    tname: &[u8],
376	) -> Result<usize, LuaError> {
377	    // C: if (luaL_getmetafield(L, arg, "__name") == LUA_TSTRING)
378	    //      typearg = lua_tostring(L, -1);
379	    //    else if (lua_type(L, arg) == LUA_TLIGHTUSERDATA)
380	    //      typearg = "light userdata";
381	    //    else
382	    //      typearg = luaL_typename(L, arg);
383	    let typearg: Vec<u8> = if get_metafield(state, arg, b"__name")? == LuaType::String {
384	        let bytes = state.peek_bytes(-1).unwrap_or_else(|| b"?".to_vec());
385	        state.pop_n(1);
386	        bytes
387	    } else if state.type_at(arg) == LuaType::LightUserData {
388	        b"light userdata".to_vec()
389	    } else {
390	        state.type_name_at(arg).to_vec()
391	    };
392	    // C: msg = lua_pushfstring(L, "%s expected, got %s", tname, typearg);
393	    // C: return luaL_argerror(L, arg, msg);
394	    let msg_owned = format!(
395	        "{} expected, got {}",
396	        BStr(tname),
397	        BStr(&typearg)
398	    );
399	    arg_error(state, arg, msg_owned.as_bytes())
400	}
