402	/// Push a type-tag error for `arg`, using the Lua type name for `tag`.
403	///
404	/// C: `static void tag_error(lua_State *L, int arg, int tag)`
405	fn tag_error(state: &mut LuaState, arg: i32, tag: LuaType) -> Result<(), LuaError> {
406	    let name = state.type_name(tag);
407	    type_error_arg(state, arg, name)?;
408	    Ok(())
409	}
