496	
497	/// Create a new metatable for type `tname` and register it in the registry.
498	/// Returns `true` (and leaves new metatable on stack) if the table was created;
499	/// returns `false` (and leaves existing table on stack) if already existed.
500	///
501	/// C: `LUALIB_API int luaL_newmetatable(lua_State *L, const char *tname)`
502	pub fn new_metatable(state: &mut LuaState, tname: &[u8]) -> Result<bool, LuaError> {
503	    // C: if (luaL_getmetatable(L, tname) != LUA_TNIL)  return 0;
504	    if get_metatable(state, tname)? != LuaType::Nil {
505	        return Ok(false); // leave previous value on top
506	    }
507	    state.pop_n(1);
508	    // C: lua_createtable(L, 0, 2);
509	    state.create_table(0, 2)?;
510	    // C: lua_pushstring(L, tname); lua_setfield(L, -2, "__name");
511	    state.push_bytes(tname)?;
512	    state.set_field(-2, b"__name")?;
513	    // C: lua_pushvalue(L, -1); lua_setfield(L, LUA_REGISTRYINDEX, tname);
514	    state.push_value(-1)?;
515	    state.set_field(LUA_REGISTRYINDEX, tname)?;
516	    Ok(true)
517	}
