519	/// Set the metatable of the value at stack top to the one registered as `tname`.
520	///
521	/// C: `LUALIB_API void luaL_setmetatable(lua_State *L, const char *tname)`
522	pub fn set_metatable(state: &mut LuaState, tname: &[u8]) -> Result<(), LuaError> {
523	    // C: luaL_getmetatable(L, tname); lua_setmetatable(L, -2);
524	    get_metatable(state, tname)?;
525	    state.set_metatable(-2)?;
526	    Ok(())
527	}
