529	/// Check whether the value at `ud` is a full userdata with metatable `tname`.
530	/// Returns `Some(userdata)` if yes, `None` otherwise.
531	///
532	/// C: `LUALIB_API void *luaL_testudata(lua_State *L, int ud, const char *tname)`
533	pub fn test_udata(
534	    state: &mut LuaState,
535	    ud: i32,
536	    tname: &[u8],
537	) -> Result<Option<GcRef<LuaUserData>>, LuaError> {
538	    // C: void *p = lua_touserdata(L, ud);
539	    let p = state.to_userdata(ud);
540	    if let Some(p) = p {
541	        // C: if (lua_getmetatable(L, ud))
542	        if state.get_metatable(ud)? {
543	            // C: luaL_getmetatable(L, tname);
544	            get_metatable(state, tname)?;
545	            // C: if (!lua_rawequal(L, -1, -2))  p = NULL;
546	            let eq = state.raw_equal(-1, -2)?;
547	            state.pop_n(2); // remove both metatables
548	            if eq {
549	                return Ok(Some(p));
550	            }
551	        }
552	    }
553	    Ok(None)
554	}
