556	/// Like `test_udata` but raises a type error if the check fails.
557	///
558	/// C: `LUALIB_API void *luaL_checkudata(lua_State *L, int ud, const char *tname)`
559	pub fn check_udata(
560	    state: &mut LuaState,
561	    ud: i32,
562	    tname: &[u8],
563	) -> Result<GcRef<LuaUserData>, LuaError> {
564	    // C: void *p = luaL_testudata(L, ud, tname);
565	    // C: luaL_argexpected(L, p != NULL, ud, tname);
566	    match test_udata(state, ud, tname)? {
567	        Some(p) => Ok(p),
568	        None => {
569	            type_error_arg(state, ud, tname)?;
570	            unreachable!()
571	        }
572	    }
573	}
