577	/// Check that `arg` is one of the strings in `lst` and return its index.
578	/// If `def` is `Some` it is used as default when `arg` is absent/nil.
579	///
580	/// C: `LUALIB_API int luaL_checkoption(lua_State *L, int arg, const char *def, const char *const lst[])`
581	pub fn check_option(
582	    state: &mut LuaState,
583	    arg: i32,
584	    def: Option<&[u8]>,
585	    lst: &[&[u8]],
586	) -> Result<usize, LuaError> {
587	    let name: Vec<u8> = match def {
588	        Some(d) if state.is_none_or_nil(arg) => d.to_vec(),
589	        _ => check_lstring(state, arg)?.as_bytes().to_vec(),
590	    };
591	    for (i, entry) in lst.iter().enumerate() {
592	        if *entry == name.as_slice() {
593	            return Ok(i);
594	        }
595	    }
596	    Err(LuaError::runtime(format_args!(
597	        "invalid option '{}'",
598	        BStr(&name)
599	    )))
