818	/// Ensure at least `sz` free bytes are available in `buf`.
819	///
820	/// C: `static char *prepbuffsize(luaL_Buffer *B, size_t sz, int boxidx)`
821	/// C: `LUALIB_API char *luaL_prepbuffsize(luaL_Buffer *B, size_t sz)`
822	pub fn prep_buff_size(buf: &mut LuaBuffer, sz: usize) -> Result<(), LuaError> {
823	    if buf.data.capacity() - buf.data.len() < sz {
824	        let newcap = new_buff_size(buf, sz)?;
825	        buf.data.reserve(newcap - buf.data.len());
826	    }
827	    Ok(())
828	}
