831	///
832	/// C: `LUALIB_API void luaL_addlstring(luaL_Buffer *B, const char *s, size_t l)`
833	pub fn add_lstring(buf: &mut LuaBuffer, s: &[u8]) {
834	    if !s.is_empty() {
835	        buf.data.extend_from_slice(s);
836	    }
