895	/// Perform global byte-string substitution: replace all occurrences of `pat`
896	/// with `repl` in `s`, appending results into `buf`.
897	///
898	/// C: `LUALIB_API void luaL_addgsub(luaL_Buffer *b, const char *s, const char *p, const char *r)`
899	pub fn add_gsub(buf: &mut LuaBuffer, s: &[u8], pat: &[u8], repl: &[u8]) {
900	    if pat.is_empty() {
901	        add_lstring(buf, s);
902	        return;
903	    }
904	    let mut remaining = s;
905	    while let Some(pos) = find_bytes(remaining, pat) {
906	        // C: luaL_addlstring(b, s, wild - s);
907	        add_lstring(buf, &remaining[..pos]);
908	        // C: luaL_addstring(b, r);
909	        add_lstring(buf, repl);
910	        remaining = &remaining[pos + pat.len()..];
911	    }
912	    // C: luaL_addstring(b, s);  /* push last suffix */
913	    add_lstring(buf, remaining);
914	}
