946	/// Store the value at the top of the stack in table `t` and return a unique
947	/// integer reference. If the value is `nil`, returns `LUA_REFNIL` without
948	/// modifying the table.
949	///
950	/// C: `LUALIB_API int luaL_ref(lua_State *L, int t)`
951	pub fn lua_ref(state: &mut LuaState, t: i32) -> Result<i32, LuaError> {
952	    // C: if (lua_isnil(L, -1)) { lua_pop(L, 1); return LUA_REFNIL; }
953	    if state.type_at(-1) == LuaType::Nil {
954	        state.pop_n(1);
955	        return Ok(LUA_REFNIL);
956	    }
957	    let t = state.abs_index(t);
958	    // C: if (lua_rawgeti(L, t, freelist) == LUA_TNIL)
959	    let ref_val: i32;
960	    if state.raw_get_i(t, FREELIST_REF)? == LuaType::Nil {
961	        ref_val = 0; // list is empty
962	        // C: lua_pushinteger(L, 0); lua_rawseti(L, t, freelist);
963	        state.push(LuaValue::Int(0));
964	        state.raw_set_i(t, FREELIST_REF)?;
965	    } else {
966	        // C: lua_assert(lua_isinteger(L, -1)); ref = (int)lua_tointeger(L, -1);
967	        debug_assert!(state.type_at(-1) == LuaType::Number);
968	        ref_val = state.to_integer_x(-1).unwrap_or(0) as i32;
969	    }
970	    state.pop_n(1); // remove element from stack
971	    let next_ref: i32;
972	    if ref_val != 0 {
973	        // C: lua_rawgeti(L, t, ref); lua_rawseti(L, t, freelist);
974	        state.raw_get_i(t, ref_val as i64)?;
975	        state.raw_set_i(t, FREELIST_REF)?;
976	        next_ref = ref_val;
977	    } else {
978	        // C: ref = (int)lua_rawlen(L, t) + 1;
979	        next_ref = (state.raw_len(t) as i32) + 1;
980	    }
981	    // C: lua_rawseti(L, t, ref);
982	    state.raw_set_i(t, next_ref as i64)?;
983	    Ok(next_ref)
984	}
