986	/// Release reference `ref` from table `t`, adding it to the free list.
987	///
988	/// C: `LUALIB_API void luaL_unref(lua_State *L, int t, int ref)`
989	pub fn lua_unref(state: &mut LuaState, t: i32, r: i32) -> Result<(), LuaError> {
990	    if r >= 0 {
991	        let t = state.abs_index(t);
992	        // C: lua_rawgeti(L, t, freelist);
993	        state.raw_get_i(t, FREELIST_REF)?;
994	        debug_assert!(state.type_at(-1) == LuaType::Number);
995	        // C: lua_rawseti(L, t, ref);  /* t[ref] = t[freelist] */
996	        state.raw_set_i(t, r as i64)?;
997	        // C: lua_pushinteger(L, ref); lua_rawseti(L, t, freelist);
998	        state.push(LuaValue::Int(r as i64));
999	        state.raw_set_i(t, FREELIST_REF)?;
1000	    }
1001	    Ok(())
1002	}
