1083	/// Push the metafield `event` of `obj` onto the stack and return its type.
1084	/// If there is no metafield, nothing is pushed and `LuaType::Nil` is returned.
1085	///
1086	/// C: `LUALIB_API int luaL_getmetafield(lua_State *L, int obj, const char *event)`
1087	pub fn get_metafield(
1088	    state: &mut LuaState,
1089	    obj: i32,
1090	    event: &[u8],
1091	) -> Result<LuaType, LuaError> {
1092	    // C: if (!lua_getmetatable(L, obj)) return LUA_TNIL;
1093	    if !state.get_metatable(obj)? {
1094	        return Ok(LuaType::Nil);
1095	    }
1096	    // C: lua_pushstring(L, event); tt = lua_rawget(L, -2);
1097	    state.push_bytes(event)?;
1098	    let tt = state.raw_get(-2)?;
1099	    if tt == LuaType::Nil {
1100	        // C: lua_pop(L, 2); /* remove metatable and metafield */
1101	        state.pop_n(2);
1102	    } else {
1103	        // C: lua_remove(L, -2); /* remove only metatable */
1104	        state.remove(-2)?;
1105	    }
1106	    Ok(tt)
1107	}
