1111	///
1112	/// C: `LUALIB_API int luaL_callmeta(lua_State *L, int obj, const char *event)`
1113	pub fn call_meta(state: &mut LuaState, obj: i32, event: &[u8]) -> Result<bool, LuaError> {
1114	    let obj = state.abs_index(obj);
1115	    // C: if (luaL_getmetafield(L, obj, event) == LUA_TNIL) return 0;
1116	    if get_metafield(state, obj, event)? == LuaType::Nil {
1117	        return Ok(false);
1118	    }
1119	    // C: lua_pushvalue(L, obj); lua_call(L, 1, 1);
1120	    state.push_value(obj)?;
1121	    state.call(1, 1)?;
1122	    Ok(true)
1123	}
