1146	/// Convert the value at `idx` to a byte-string representation (using `__tostring`
1147	/// if available) and push it onto the stack.
1148	///
1149	/// C: `LUALIB_API const char *luaL_tolstring(lua_State *L, int idx, size_t *len)`
1150	pub fn to_lua_string(state: &mut LuaState, idx: i32) -> Result<Vec<u8>, LuaError> {
1151	    let idx = state.abs_index(idx);
1152	    // C: if (luaL_callmeta(L, idx, "__tostring"))
1153	    if call_meta(state, idx, b"__tostring")? {
1154	        // C: if (!lua_isstring(L, -1)) luaL_error(...)
1155	        if state.type_at(-1) != LuaType::String {
1156	            return Err(LuaError::runtime(format_args!(
1157	                "'__tostring' must return a string"
1158	            )));
1159	        }
1160	    } else {
1161	        match state.type_at(idx) {
1162	            LuaType::Number => {
1163	                // C: if (lua_isinteger(L, idx)) lua_pushfstring(L, "%I", ...)
1164	                if state.is_integer(idx) {
1165	                    let i = state.to_integer_x(idx).unwrap_or(0);
1166	                    state.push_fstring(format_args!("{}", i))?;
1167	                } else {
1168	                    let f = state.to_number_x(idx).unwrap_or(0.0);
1169	                    state.push_fstring(format_args!("{:?}", f))?;
1170	                }
1171	            }
1172	            LuaType::String => {
1173	                // C: lua_pushvalue(L, idx);
1174	                state.push_value(idx)?;
1175	            }
1176	            LuaType::Boolean => {
1177	                let b = state.to_boolean(idx);
1178	                state.push_string(if b { b"true" } else { b"false" })?;
1179	            }
1180	            LuaType::Nil => {
1181	                state.push_string(b"nil")?;
1182	            }
1183	            _ => {
1184	                // C: int tt = luaL_getmetafield(L, idx, "__name");
1185	                let tt = get_metafield(state, idx, b"__name")?;
1186	                let kind: Vec<u8> = if tt == LuaType::String {
1187	                    state.peek_bytes(-1).unwrap_or_else(|| b"?".to_vec())
1188	                } else {
1189	                    state.type_name_at(idx).to_vec()
1190	                };
1191	                // C: lua_pushfstring(L, "%s: %p", kind, lua_topointer(L, idx));
1192	                // TODO(port): lua_topointer gives a pointer address; in Rust use
1193	                // a hash or allocation address for a stable identifier.
1194	                state.push_fstring(format_args!("{}: 0x?", BStr(&kind)))?;
1195	                if tt != LuaType::Nil {
1196	                    // C: lua_remove(L, -2);
1197	                    state.remove(-2)?;
1198	                }
1199	            }
1200	        }
1201	    }
1202	    // C: return lua_tolstring(L, -1, len);
1203	    Ok(state.peek_bytes(-1).unwrap_or_default())
1204	}
