1239	/// Ensure `state[idx][fname]` is a table; push it.
1240	/// Returns `true` if the table already existed, `false` if newly created.
1241	///
1242	/// C: `LUALIB_API int luaL_getsubtable(lua_State *L, int idx, const char *fname)`
1243	pub fn get_subtable(
1244	    state: &mut LuaState,
1245	    idx: i32,
1246	    fname: &[u8],
1247	) -> Result<bool, LuaError> {
1248	    if state.get_field(idx, fname)? == LuaType::Table {
1249	        return Ok(true);
1250	    }
1251	    state.pop_n(1);
1252	    let idx = state.abs_index(idx);
1253	    let new_tbl = state.new_table();
1254	    state.push(LuaValue::Table(new_tbl));
1255	    state.push_value(-1)?;
1256	    state.set_field(idx, fname)?;
1257	    Ok(false)
1258	}
